use std::collections::VecDeque;

struct TreeNode {
    val: i32,
    left: Option<Box<TreeNode>>,
    right: Option<Box<TreeNode>>,
}

impl TreeNode {
    fn new(val: i32) -> Self {
        TreeNode { val, left: None, right: None }
    }
}

fn build_tree(arr: &[Option<i32>]) -> Option<Box<TreeNode>> {
    if arr.is_empty() || arr[0].is_none() {
        return None;
    }

    let mut root = Box::new(TreeNode::new(arr[0].unwrap()));
    let mut queue: VecDeque<*mut TreeNode> = VecDeque::new();
    queue.push_back(&mut *root as *mut TreeNode);
    let mut i = 1;

    while let Some(node_ptr) = queue.pop_front() {
        let node = unsafe { &mut *node_ptr };
        if i < arr.len() {
            if let Some(val) = arr[i] {
                node.left = Some(Box::new(TreeNode::new(val)));
                queue.push_back(&mut **node.left.as_mut().unwrap() as *mut TreeNode);
            }
        }
        i += 1;
        if i < arr.len() {
            if let Some(val) = arr[i] {
                node.right = Some(Box::new(TreeNode::new(val)));
                queue.push_back(&mut **node.right.as_mut().unwrap() as *mut TreeNode);
            }
        }
        i += 1;
    }
    Some(root)
}

fn level_order_traversal(arr: &[Option<i32>]) -> Vec<i32> {
    let root = match build_tree(arr) {
        Some(r) => r,
        None => return vec![],
    };

    let mut result = Vec::new();
    let mut queue: VecDeque<&TreeNode> = VecDeque::new();
    queue.push_back(&root);

    while let Some(node) = queue.pop_front() {
        result.push(node.val);
        if let Some(ref left) = node.left {
            queue.push_back(left);
        }
        if let Some(ref right) = node.right {
            queue.push_back(right);
        }
    }
    result
}

fn main() {
    let arr = vec![Some(1), Some(2), Some(3), Some(4), Some(5), Some(6), Some(7)];
    println!("Level order: {:?}", level_order_traversal(&arr));
}

import scala.collection.mutable

object BinaryTree {
  class TreeNode(val value: Int) {
    var left: TreeNode = _
    var right: TreeNode = _
  }

  def buildTree(arr: Array[Option[Int]]): Option[TreeNode] = {
    if (arr.isEmpty || arr(0).isEmpty) return None

    val root = new TreeNode(arr(0).get)
    val queue = mutable.Queue[TreeNode](root)
    var i = 1

    while (queue.nonEmpty && i < arr.length) {
      val node = queue.dequeue()
      if (i < arr.length && arr(i).isDefined) {
        node.left = new TreeNode(arr(i).get)
        queue.enqueue(node.left)
      }
      i += 1
      if (i < arr.length && arr(i).isDefined) {
        node.right = new TreeNode(arr(i).get)
        queue.enqueue(node.right)
      }
      i += 1
    }
    Some(root)
  }

  def levelOrderTraversal(arr: Array[Option[Int]]): List[Int] = {
    buildTree(arr) match {
      case None => List.empty
      case Some(root) =>
        val result = mutable.ListBuffer[Int]()
        val queue = mutable.Queue[TreeNode](root)
        while (queue.nonEmpty) {
          val node = queue.dequeue()
          result += node.value
          if (node.left != null) queue.enqueue(node.left)
          if (node.right != null) queue.enqueue(node.right)
        }
        result.toList
    }
  }

  def main(args: Array[String]): Unit = {
    val arr = Array[Option[Int]](Some(1), Some(2), Some(3), Some(4), Some(5), Some(6), Some(7))
    println(s"Level order: ${levelOrderTraversal(arr)}")
  }
}

class TreeNode {
    var val: Int
    var left: TreeNode?
    var right: TreeNode?

    init(_ val: Int) {
        self.val = val
    }
}

func buildTree(_ arr: [Int?]) -> TreeNode? {
    if arr.isEmpty || arr[0] == nil { return nil }

    let root = TreeNode(arr[0]!)
    var queue = [root]
    var i = 1

    while !queue.isEmpty && i < arr.count {
        let node = queue.removeFirst()
        if i < arr.count, let val = arr[i] {
            node.left = TreeNode(val)
            queue.append(node.left!)
        }
        i += 1
        if i < arr.count, let val = arr[i] {
            node.right = TreeNode(val)
            queue.append(node.right!)
        }
        i += 1
    }
    return root
}

func levelOrderTraversal(_ arr: [Int?]) -> [Int] {
    guard let root = buildTree(arr) else { return [] }

    var result = [Int]()
    var queue = [root]

    while !queue.isEmpty {
        let node = queue.removeFirst()
        result.append(node.val)
        if let left = node.left { queue.append(left) }
        if let right = node.right { queue.append(right) }
    }
    return result
}

